var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`하수인아… 하수인아!`,JPN:`下僕よ……下僕よ！`,ENG:`My subject... My subject!`,TWN:`手下…手下！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`으음…….`,JPN:`ううん……`,ENG:`Mmm...`,TWN:`嗯……`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`모모? 무슨 일이에요?`,JPN:`モモ？　どうしたんですか？`,ENG:`Momo? What is it?`,TWN:`莫莫？有什麼事嗎？`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`MOMO_BAR_NULL_NULL`,text:{KOREA:`아앗! 깨어났다!`,JPN:`あっ！　起きたか！`,ENG:`Ah, you're awake!`,TWN:`哇喔！你終於醒啦？！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`MOMO_BAR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`MOMO_BAR_NULL_NULL`,text:{KOREA:`정말 다행이구나!`,JPN:`本当によかったぞ！`,ENG:`I am so glad!`,TWN:`還好你沒事！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`MOMO_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`MOMO_BAR_NULL_NULL`,text:{KOREA:`이 몸이 스스로 일어날 때까지 깨워주지 않아서 걱정했도다!`,JPN:`吾輩が自分で起きるまで起こしてくれないから心配した！`,ENG:`I was worried because you didn't wake me up until I woke up on my own.`,TWN:`本王起床的時候，發現你怎麼沒有叫我，害我還很擔心你！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`MOMO_BAR_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`그게 무슨 소리죠? 아침 일찍부터…….`,JPN:`どういう意味ですか？　朝早くから……`,ENG:`What are you talking about? Why are you up so early?`,TWN:`你在說什麼？不是還早嗎……`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`MOMO_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`MOMO_BAR_NULL_NULL`,text:{KOREA:`아침이 아니다. 지금은 해가 지고 있느니라.`,JPN:`朝ではない。もう日が暮れているのだ。`,ENG:`It's not early. The sun's going down already.`,TWN:`不早啦，太陽都下山了～`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`MOMO_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`네…? 그럴 리가…`,JPN:`はい……？　そんなはずが……`,ENG:`What? No way.`,TWN:`什麼…？怎麼可能…`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`MOMO_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`아아앗?! 벌써 가게 오픈 시간이잖아요?!`,JPN:`ああっ！　もう店のオープン時間じゃないですか！？`,ENG:`Wah! It's already time to open the shop!`,TWN:`啊啊啊！開店的時間到了！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`MOMO_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`이럴 때가 아니라 빨리 영업 준비를 해야… 우앗!`,JPN:`こうしている場合じゃありません、早く営業準備をしないと……うわっ！`,ENG:`I must get ready for work—wah!`,TWN:`不跟你說了，我要趕快去準備開店…哎唷喂！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`MOMO_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`MOMO_BAR_NULL_NULL`,text:{KOREA:`니콜이 허둥대다 넘어지다니, 사천왕답지 못하구나.`,JPN:`ニコルが慌てて転ぶなんて、四天王らしくないな。`,ENG:`Nicole, you panicked and tripped. Not like my Champion.`,TWN:`妮可，你這樣慌慌張張的，還跌倒！這樣怎麼當本王的手下！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`MOMO_BAR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`MOMO_BAR_NULL_NULL`,text:{KOREA:`이번만 이 몸이 특별히 옷 입는 걸 도와주도록 하마!`,JPN:`今回だけ吾輩が特別に服を着るのを手伝ってやろう！`,ENG:`Here, I'll help you get dressed just this once.`,TWN:`這次本王就特別禮遇你，幫你穿衣服吧！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`MOMO_BAR_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`괜찮아요! 지금 당장 갈아입고 나갈 테니까요!`,JPN:`大丈夫です！　今すぐ着替えて出ますから！`,ENG:`I’m fine! I can get changed and leave right away!`,TWN:`不用啦！我自己換一換就好，趕著出門呢！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`MOMO_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`휴우…`,JPN:`ふう……`,ENG:`Whew...`,TWN:`呼…`},stage:{bg:`GREMORY_BAR`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`정말 이상하네요. 제가 늦잠을 자다니.`,JPN:`本当におかしいですね。私が寝坊をするなんて。`,ENG:`I don't understand why I slept in.`,TWN:`真奇怪，我竟然會睡過頭？`},stage:{bg:`GREMORY_BAR`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};